import{_ as a,o as d,c as e,ag as o}from"./chunks/framework.BZohXCq9.js";const q=JSON.parse('{"title":"短剧改编","description":"","frontmatter":{"title":"短剧改编","outline":false},"headers":[],"relativePath":"novels/jin-gu-yao/drama/index.md","filePath":"novels/jin-gu-yao/drama/index.md","lastUpdated":1774160915000}'),r={name:"novels/jin-gu-yao/drama/index.md"};function n(l,t,h,i,s,u){return d(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="短剧改编" tabindex="-1">短剧改编 <a class="header-anchor" href="#短剧改编" aria-label="Permalink to &quot;短剧改编&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">改编说明</p><p>将小说《金鼓谣》改编为竖屏短剧。每集 3-5 分钟，每集结尾设&quot;钩子&quot;悬念。</p></div><h2 id="改编策略" tabindex="-1">改编策略 <a class="header-anchor" href="#改编策略" aria-label="Permalink to &quot;改编策略&quot;">​</a></h2><p>原小说是&quot;倒叙回忆 → 日常 → 变局&quot;的慢节奏叙事。短剧改为<strong>倒叙开场法</strong>——先给最炸的画面，再回头讲&quot;她怎么走到这一步&quot;。观众先被勾住，再愿意看她的前史。</p><p><strong>核心原则</strong>：不是&quot;加戏&quot;，而是&quot;重新剪辑&quot;。原小说所有的好东西都在——只是换了一种呈现顺序。</p><h2 id="第一季-长安-序章-第一章改编" tabindex="-1">第一季：长安（序章 + 第一章改编） <a class="header-anchor" href="#第一季-长安-序章-第一章改编" aria-label="Permalink to &quot;第一季：长安（序章 + 第一章改编）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>集数</th><th>标题</th><th>钩子类型</th><th>对应原著</th></tr></thead><tbody><tr><td><a href="/novels/jin-gu-yao/drama/01.html">第 1 集</a></td><td>缝不完的袍子</td><td>悬念 + 身份反转</td><td>第一章前半</td></tr><tr><td><a href="/novels/jin-gu-yao/drama/02.html">第 2 集</a></td><td>月亮与槐花</td><td>情感冲击 + 闪回</td><td>第一章（离别）</td></tr><tr><td><a href="/novels/jin-gu-yao/drama/03.html">第 3 集</a></td><td>八岁那年的马</td><td>揭秘 + 暗处威胁</td><td>序章全部</td></tr><tr><td><a href="/novels/jin-gu-yao/drama/04.html">第 4 集</a></td><td>天亮之前</td><td>紧张感 + 倒计时</td><td>第一章（出城）</td></tr><tr><td><a href="/novels/jin-gu-yao/drama/05.html">第 5 集</a></td><td>两盘棋</td><td>双线交汇 + 大悬念</td><td>原创过渡</td></tr></tbody></table><h2 id="钩子设计" tabindex="-1">钩子设计 <a class="header-anchor" href="#钩子设计" aria-label="Permalink to &quot;钩子设计&quot;">​</a></h2><table tabindex="0"><thead><tr><th>集数</th><th>结尾钩子</th></tr></thead><tbody><tr><td>第 1 集</td><td>&quot;这件事，她已经等了很多年&quot; — 揭示三娘不是被动应对</td></tr><tr><td>第 2 集</td><td>突切八岁摔马画面 + &quot;说完这话第二年，母亲就死了&quot;</td></tr><tr><td>第 3 集</td><td>鄠县县衙有人在地图上标记李氏庄园 — &quot;有人比她更早看到了那封信&quot;</td></tr><tr><td>第 4 集</td><td>鄠县县令派人监视 — &quot;她以为自己在布局，有人棋更早&quot;</td></tr><tr><td>第 5 集</td><td>分屏对峙 — &quot;她以为是起点，他以为是陷阱。都对了。&quot;</td></tr></tbody></table>',9)])])}const c=a(r,[["render",n]]);export{q as __pageData,c as default};
